const body = $input.first().json;
const errorMsg = (body.error_message || '').trim();
if (!errorMsg || errorMsg.length < 5) return [{ json: { valid: false, error: 'Error message required' } }];
return [{ json: { valid: true, error_message: errorMsg, context: body.context || '' } }];

const dbResults = $input.all();
const hasResults = dbResults.length > 0 && dbResults[0].json && dbResults[0].json.id;
const inputData = $('Validate').first().json;
return [{ json: { has_db_result: hasResults, db_results: hasResults ? dbResults.map(r => r.json) : [], error_message: inputData.error_message, context: inputData.context } }];

const res = $input.first().json;
const checkData = $('Has DB Result?').first().json;
const content = res?.choices?.[0]?.message?.content || '';
let analysis;
try {
  const clean = content.replace(/```json|```/g,'').trim();
  analysis = JSON.parse(clean.match(/\{[\s\S]*\}/)?.[0] || clean);
} catch {
  analysis = { title: 'Error Analysis', description: content, root_cause: '', fix_steps: [], category: 'General', severity: 'medium' };
}
return [{ json: { success: true, source: 'ai_generated', ...analysis, model: res.model, error_message: checkData.error_message } }];
